function ApplicationFormSection({ path, t }) {
  return (
    <section id="applicationForm" className={styles.applicationForm}>
      <h1>{t("applicationForm.title")}</h1>
      <p>{t("applicationForm.subtitle")}</p>
      <div className={styles.container}>
        <div className={styles.banner}>
          <div className={styles.journey}>
            <h1>{t("journey.title")}</h1>
            <div className={styles.steps}>
              <article className={styles.step}>
                <h3>{t("journey.steps.fillForm.title")}</h3>
                <p>{t("journey.steps.fillForm.description")}</p>
              </article>
              <article className={styles.step}>
                <h3>{t("journey.steps.review.title")}</h3>
                <p>{t("journey.steps.review.description")}</p>
              </article>
              <article className={styles.step}>
                <h3>{t("journey.steps.contact.title")}</h3>
                <p>{t("journey.steps.contact.description")}</p>
              </article>
              <article className={styles.step}>
                <h3>{t("journey.steps.start.title")}</h3>
                <p>{t("journey.steps.start.description")}</p>
              </article>
            </div>
            <img src={bannerImg} alt="" />
          </div>
        </div>
        <ApplicationForm path={path} styles={styles} />
      </div>
    </section>
  );
}

function JoinUsPage() {
  const [path, setPath] = useState("");
  const { t } = useTranslation("volunteer_page");
  const { contributor } = useParams();
  const sectionRef = useRef(null);

  useEffect(() => {
    if(contributor === "member" || contributor === "volunteer") {
      sectionRef.current?.scrollIntoView({
        behavior: "smooth",
        block: "start",
      });
    }
  }, []);

  return (
    <>
      <div className={styles.joinUsPage}>
        {/* <img src={mountainImg} className={styles.pageBg}/> */}

        <PageHero title={t("hero")} heroImg={mountainImg} />
        {/* SECTION 1: FOCUS AREA */}

        <FocusAreasSection t={t} />

        {/* SECTION 2: WHY JOIN US */}

        <JoinUsSection t={t} />

        {/* SECTION 3: LIFE AT TIFAOUINE */}

        <LifeAtTifaouineSection t={t} />

        {/* SECTION 5: CHOOSE YOUR PATH */}

        <ChoseYourPathSection
          sectionRef={sectionRef}
          t={t}
          path={path}
          setPath={setPath}
        />

        {/* SECTION 6: APPLICATION FORM */}
        {path !== "" && <ApplicationFormSection t={t} path={path} />}
      </div>
    </>
  );
}

export default JoinUsPage;
